#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char S[12]; // up to 10 digits + '\0' + safety
        scanf("%11s",S);
        long long num=0;
        for(int i=0; S[i]!='\0'; ++i){
            num = num*10 + (S[i]-'0');
        }
        printf("%lld\n",num);
    }
    return 0;
}

